mapper.select:
SELECT C.SSPS_DL_CRT_DT, C.SSPS_DL_ID, C.SSPS_TYP_CD, C.RPR_PRGRS_CCD, C.RSK_GRD_CD, C.SCNR_MRK, C.FIU_RPT_NO, C.FIU_RPT_DT, P.DL_P_NM, P.DL_P_RNMCNO, COALESCE(A.DL_AMT, 0) AS DL_AMT, COALESCE(T.DL_CNT, 0) AS DL_CNT FROM NIC66B C LEFT JOIN NIC70B P ON P.SSPS_DL_CRT_DT = C.SSPS_DL_CRT_DT AND P.DL_P_RNMCNO = C.DL_P_RNMCNO LEFT JOIN ( SELECT SSPS_DL_CRT_DT, SSPS_DL_ID, SUM(DL_AMT) AS DL_AMT FROM NIC75B GROUP BY SSPS_DL_CRT_DT, SSPS_DL_ID ) A ON A.SSPS_DL_CRT_DT = C.SSPS_DL_CRT_DT AND A.SSPS_DL_ID = C.SSPS_DL_ID LEFT JOIN ( SELECT SSPS_DL_CRT_DT, SSPS_DL_ID, COUNT(*) AS DL_CNT FROM NIC73B GROUP BY SSPS_DL_CRT_DT, SSPS_DL_ID ) T ON T.SSPS_DL_CRT_DT = C.SSPS_DL_CRT_DT AND T.SSPS_DL_ID = C.SSPS_DL_ID WHERE C.SSPS_DL_CRT_CCD = 'CTR'
AND C.SSPS_DL_CRT_DT >= #{stDate}
AND C.SSPS_DL_CRT_DT <= #{edDate}
AND C.RPR_PRGRS_CCD = #{rprPrgrsCcd}
ORDER BY C.SSPS_DL_CRT_DT DESC, C.SSPS_DL_ID DESC LIMIT #{size} OFFSET #{offset}

SELECT COUNT(*)
FROM NIC66B C
WHERE C.SSPS_DL_CRT_CCD = 'CTR'

    AND C.SSPS_DL_CRT_DT >= #{stDate}


    AND C.SSPS_DL_CRT_DT <= #{edDate}


    AND C.RPR_PRGRS_CCD = #{rprPrgrsCcd}

SELECT
    SSPS_DL_CRT_DT, SSPS_DL_ID, GNL_AC_NO, DL_AMT, DL_CCY
FROM NIC75B
WHERE SSPS_DL_CRT_DT = #{sspsDlCrtDt}
  AND SSPS_DL_ID      = #{sspsDlId}
ORDER BY GNL_AC_NO
